Create the relative-path source resolver in the server install pipeline. When a marketplace was cloned as a whole (the user added the registry repo as a marketplace source), relative-path plugins are already on disk and no new clone is needed.

**File to create**: `apps/server/src/services/marketplace/source-resolvers/relative-path.ts`

```typescript
/**
 * Relative-path source resolver. Resolves a plugin already present in the
 * cloned marketplace tree. No clone, no fetch — just a path join + exists check.
 *
 * @module services/marketplace/source-resolvers/relative-path
 */

import path from 'node:path';
import { access } from 'node:fs/promises';
import type { ResolvedSourceDescriptor } from '@dorkos/marketplace';
import type { FetchedPackage, FetchPackageOptions } from '../package-fetcher.js';
import { PackageNotFoundError } from '../errors.js';

export async function relativePathResolver(
  resolved: Extract<ResolvedSourceDescriptor, { type: 'relative-path' }>,
  opts: FetchPackageOptions
): Promise<FetchedPackage> {
  const fullPath = path.join(resolved.marketplaceRoot, resolved.path);
  try {
    await access(fullPath);
  } catch {
    throw new PackageNotFoundError(
      `Plugin path ${resolved.path} not found in marketplace root ${resolved.marketplaceRoot}`
    );
  }
  return { path: fullPath, commitSha: 'relative-path', fromCache: true };
}
```

The `commitSha: 'relative-path'` sentinel indicates that this resolver does not produce a real commit SHA. The cache layer (`marketplace-cache.ts`) treats this as a bypass — relative-path plugins are not cached separately because they live inside an already-cached marketplace clone.

