**New `fetchPackage` dispatch**:

```typescript
async fetchPackage(opts: FetchPackageOptions): Promise<FetchedPackage> {
  const resolved = resolvePluginSource(opts.source, {
    marketplaceRoot: opts.marketplaceRoot,
    pluginRoot: opts.pluginRoot,
  });

  switch (resolved.type) {
    case 'relative-path':
      return relativePathResolver(resolved, opts);
    case 'github':
      return githubResolver(resolved, opts, this.deps);
    case 'url':
      return urlResolver(resolved, opts, this.deps);
    case 'git-subdir':
      return gitSubdirResolver(resolved, opts, this.deps);
    case 'npm':
      return npmResolver(resolved, opts);
  }
}
```

